+fn baseline_checklist(release_tag: &str) -> ReleaseChecklist {
+    let items = required_checklist_items()
+        .iter()
+        .map(|required| ChecklistItem {
+            item_id: required.item_id.to_string(),
+            category: required.category,
+            required: true,
